<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  :root {
    --bg: #f0f2f5;
    --col-bg: #ebecf0;
    --card-bg: #ffffff;
    --accent: #0079bf;
    --text: #172b4d;
    --muted: #5e6c84;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: var(--bg);
    color: var(--text);
    min-height: 100vh;
  }
  header.app-header {
    padding: 20px 28px;
    background: var(--accent);
    color: #fff;
  }
  header.app-header h1 { margin: 0; font-size: 22px; font-weight: 600; }
  .toolbar {
    display: flex;
    gap: 10px;
    padding: 18px 28px;
    align-items: center;
  }
  #new-card {
    flex: 0 1 320px;
    padding: 10px 12px;
    border: 1px solid #c1c7d0;
    border-radius: 6px;
    font-size: 14px;
    outline: none;
  }
  #new-card:focus { border-color: var(--accent); box-shadow: 0 0 0 2px rgba(0,121,191,0.2); }
  #add-card {
    padding: 10px 18px;
    background: var(--accent);
    color: #fff;
    border: none;
    border-radius: 6px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
  }
  #add-card:hover { background: #026aa7; }
  .board {
    display: flex;
    gap: 18px;
    padding: 8px 28px 40px;
    align-items: flex-start;
    flex-wrap: wrap;
  }
  .column {
    background: var(--col-bg);
    border-radius: 10px;
    width: 300px;
    display: flex;
    flex-direction: column;
    max-height: 78vh;
  }
  .column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 14px 16px;
    font-weight: 600;
    font-size: 15px;
  }
  .count {
    background: rgba(9,30,66,0.13);
    color: var(--muted);
    border-radius: 12px;
    padding: 2px 10px;
    font-size: 13px;
    font-weight: 600;
    min-width: 24px;
    text-align: center;
  }
  .cards {
    padding: 4px 12px 14px;
    overflow-y: auto;
    flex: 1;
    min-height: 60px;
  }
  .column.drag-over .cards {
    background: rgba(0,121,191,0.08);
    border-radius: 8px;
  }
  .card {
    background: var(--card-bg);
    border-radius: 8px;
    padding: 12px 14px;
    margin-bottom: 10px;
    box-shadow: 0 1px 2px rgba(9,30,66,0.2);
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    gap: 8px;
    cursor: grab;
    transition: box-shadow 0.15s, transform 0.05s;
  }
  .card:hover { box-shadow: 0 3px 6px rgba(9,30,66,0.28); }
  .card.dragging { opacity: 0.5; transform: rotate(1.5deg); }
  .card-title {
    font-size: 14px;
    line-height: 1.4;
    word-break: break-word;
    flex: 1;
  }
  .card-del {
    background: transparent;
    border: none;
    color: var(--muted);
    cursor: pointer;
    font-size: 16px;
    line-height: 1;
    padding: 2px 4px;
    border-radius: 4px;
    flex-shrink: 0;
  }
  .card-del:hover { background: #ffe0e0; color: #c0392b; }
</style>
</head>
<body>
  <header class="app-header">
    <h1>Kanban Board</h1>
  </header>

  <div class="toolbar">
    <input id="new-card" type="text" placeholder="Enter a card title…" autocomplete="off">
    <button id="add-card">Add Card</button>
  </div>

  <main class="board">
    <section class="column" id="col-todo" data-col="todo">
      <div class="column-header">
        <span>To Do</span>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>

    <section class="column" id="col-doing" data-col="doing">
      <div class="column-header">
        <span>Doing</span>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>

    <section class="column" id="col-done" data-col="done">
      <div class="column-header">
        <span>Done</span>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
  </main>

<script>
(function () {
  "use strict";

  const STORAGE_KEY = "kanban.board.v1";
  const COLUMNS = ["todo", "doing", "done"];

  // state: array of { id, title, col }
  let cards = [];

  function loadState() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      const parsed = JSON.parse(raw);
      if (!Array.isArray(parsed)) return [];
      return parsed
        .filter(c => c && typeof c.title === "string" && COLUMNS.includes(c.col))
        .map(c => ({ id: String(c.id), title: c.title, col: c.col }));
    } catch (e) {
      return [];
    }
  }

  function saveState() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(cards));
    } catch (e) { /* ignore */ }
  }

  let idCounter = 0;
  function makeId() {
    idCounter += 1;
    return "card-" + idCounter + "-" + (performance.now() | 0);
  }

  function columnEl(col) {
    return document.getElementById("col-" + col);
  }
  function cardsContainer(col) {
    return columnEl(col).querySelector(".cards");
  }

  function buildCardEl(card) {
    const el = document.createElement("div");
    el.className = "card";
    el.setAttribute("draggable", "true");
    el.dataset.id = card.id;

    const title = document.createElement("span");
    title.className = "card-title";
    title.textContent = card.title;

    const del = document.createElement("button");
    del.className = "card-del";
    del.type = "button";
    del.setAttribute("aria-label", "Delete card");
    del.textContent = "✕";

    el.appendChild(title);
    el.appendChild(del);
    return el;
  }

  function render() {
    COLUMNS.forEach(col => { cardsContainer(col).innerHTML = ""; });
    cards.forEach(card => {
      cardsContainer(card.col).appendChild(buildCardEl(card));
    });
    updateCounts();
  }

  function updateCounts() {
    COLUMNS.forEach(col => {
      const n = cards.filter(c => c.col === col).length;
      columnEl(col).querySelector(".count").textContent = String(n);
    });
  }

  function addCard(title) {
    const t = title.trim();
    if (!t) return;
    cards.push({ id: makeId(), title: t, col: "todo" });
    saveState();
    render();
  }

  function deleteCard(id) {
    cards = cards.filter(c => c.id !== id);
    saveState();
    render();
  }

  function moveCard(id, col) {
    const card = cards.find(c => c.id === id);
    if (!card || !COLUMNS.includes(col)) return;
    if (card.col === col) return;
    card.col = col;
    saveState();
    render();
  }

  // --- Add card wiring ---
  const input = document.getElementById("new-card");
  const addBtn = document.getElementById("add-card");

  addBtn.addEventListener("click", function () {
    addCard(input.value);
    input.value = "";
    input.focus();
  });
  input.addEventListener("keydown", function (e) {
    if (e.key === "Enter") {
      addCard(input.value);
      input.value = "";
    }
  });

  // --- Delete (event delegation) ---
  document.querySelector(".board").addEventListener("click", function (e) {
    const del = e.target.closest(".card-del");
    if (!del) return;
    const cardEl = del.closest(".card");
    if (cardEl) deleteCard(cardEl.dataset.id);
  });

  // --- Drag and drop ---
  let draggingId = null;

  document.querySelector(".board").addEventListener("dragstart", function (e) {
    const cardEl = e.target.closest(".card");
    if (!cardEl) return;
    draggingId = cardEl.dataset.id;
    cardEl.classList.add("dragging");
    if (e.dataTransfer) {
      e.dataTransfer.effectAllowed = "move";
      e.dataTransfer.setData("text/plain", draggingId);
    }
  });

  document.querySelector(".board").addEventListener("dragend", function (e) {
    const cardEl = e.target.closest(".card");
    if (cardEl) cardEl.classList.remove("dragging");
    draggingId = null;
    COLUMNS.forEach(col => columnEl(col).classList.remove("drag-over"));
  });

  COLUMNS.forEach(col => {
    const colEl = columnEl(col);

    colEl.addEventListener("dragover", function (e) {
      e.preventDefault();
      if (e.dataTransfer) e.dataTransfer.dropEffect = "move";
      colEl.classList.add("drag-over");
    });

    colEl.addEventListener("dragleave", function (e) {
      if (!colEl.contains(e.relatedTarget)) {
        colEl.classList.remove("drag-over");
      }
    });

    colEl.addEventListener("drop", function (e) {
      e.preventDefault();
      colEl.classList.remove("drag-over");
      let id = draggingId;
      if (!id && e.dataTransfer) id = e.dataTransfer.getData("text/plain");
      if (id) moveCard(id, col);
    });
  });

  // --- Init ---
  cards = loadState();
  render();
})();
</script>
</body>
</html>
